import { Workflow, Agent, tool } from 'mastra';

const ragWorkflow = new Workflow({
  nodes: {
    planner: new Agent({
      name: 'queryPlanner',
      model: 'gpt-4o',
      instructions: 'Decompose into subqueries with sources',
    }),
    retriever: new Agent({
      tools: [searchTool, vectorSearchTool],
    }),
    synthesizer: new Agent({
      instructions: 'Synthesize with citations from {{retriever.output}}',
    }),
  },
  edges: [{ from: 'planner', to: 'retriever' }, { from: 'retriever', to: 'synthesizer' }],
});

@tool()
async function searchTool(query: string) {
  // Vector store retrieval
  return { chunks: [], source: 'vector_db' };
}

const plannerAgent = new Agent({
  instructions: `Given query: {{input.query}}
1. Identify key entities
2. Generate 2-4 subqueries
3. Assign sources (web|docs|db)
Output JSON only.`,
  outputParser: z.object({
    subqueries: z.array(z.object({
      query: z.string(),
      source: z.enum(['web', 'docs', 'db']),
    })),
  }),
});

@tool()
async function vectorSearch(query: string) {
  const results = await vectorStore.similaritySearch(query, 5);
  return {
    chunks: results.map(r => ({ text: r.pageContent, metadata: r.metadata })),
    source: 'internal_docs',
  };
}

@tool()
async function webSearch(query: string) {
  const results = await tavily.search(query);
  return {
    chunks: results.results.map(r => ({ text: r.content, url: r.url })),
    source: 'web',
  };
}

const synthesizer = new Agent({
  instructions: `Synthesize answer from sources: {{retriever.chunks}}
Rules:
- Cite every claim with [source_id:chunk_index]
- Flag contradictions
- Use only provided context`,
  outputParser: z.object({
    answer: z.string(),
    citations: z.array(z.object({
      claim: z.string(),
      source_id: z.string(),
      chunk_index: z.number(),
    })),
  }),
});

