import { Vex } from '@vex_dev/sdk';

const vex = new Vex({ apiKey: process.env.VEX_API_KEY });

const verifiedPlanner = async (input: any) => {
  const result = await ragWorkflow.planner.call(input);

  const check = await vex.verify({
    data: result,
    tests: {
      schema: 'subquery_plan',
      hallucination: { threshold: 0.1 },
      query_planning_accuracy: {
        input_query: input.query,
        planned_queries: result.subqueries,
      },
    },
  });

  if (!check.passes) throw new Error('Planning failed verification');
  return result;
};

const verifiedRetriever = async (subqueries: any[]) => {
  const results = await Promise.all(
    subqueries.map(async (sq) => {
      const toolResult = sq.source === 'web' ? 
        await webSearch(sq.query) : 
        await vectorSearch(sq.query);

      const check = await vex.verify({
        data: toolResult,
        tests: {
          source_faithfulness: {
            query: sq.query,
            retrieved_content: toolResult.chunks,
          },
          schema: 'retrieval_result',
        },
      });

      if (!check.passes) {
        console.warn(`Failed retrieval verification for ${sq.query}`);
      }
      return toolResult;
    })
  );
  return { chunks: results.flatMap(r => r.chunks), sources: results };
};

const verifiedSynthesis = async (chunks: any[], sources: any[]) => {
  const synthResult = await synthesizer.call({ chunks });

  const finalCheck = await vex.verify({
    data: synthResult,
    tests: {
      hallucination_detection: {
        response: synthResult.answer,
        ground_truth: chunks.map(c => c.text),
      },
      citation_verification: {
        citations: synthResult.citations,
        sources,
      },
      cross_source_consistency: {
        all_chunks: chunks,
        response_claims: extractClaims(synthResult.answer),
      },
    },
  });

  return finalCheck.passes ? synthResult : null;
};
